import{_ as o,o as C,c as D,k as P,a as H,t,Q as a}from"./chunks/framework.1b6086f5.js";const c="/assets/DHCP知识图谱.dd4a5260.png",m=JSON.parse('{"title":"DHCP详解","description":"","frontmatter":{"title":"DHCP详解"},"headers":[],"relativePath":"doc/网络协议/DHCP/DHCP.md","filePath":"packages/doc/src/网络协议/DHCP/DHCP.md","lastUpdated":1704643216000}'),d={name:"doc/网络协议/DHCP/DHCP.md"},p={id:"frontmatter-title",tabindex:"-1"},l=P("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":'Permalink to "{{ $frontmatter.title }}"'},"​",-1),i=a('<p><img src="'+c+'" alt="DHCP知识图谱"></p><h2 id="认识-dhcp" tabindex="-1">认识 DHCP <a class="header-anchor" href="#认识-dhcp" aria-label="Permalink to &quot;认识 DHCP&quot;">​</a></h2><p><code>DHCP</code> 的全称是 <code>Dynamic Host Configuration Protocol</code> 动态主机配置协议。</p><ul><li>实现自动设置 IP 地址、统一管理 IP 地址分配</li><li>节省时间，减少手动配置出错几率</li></ul><p>DHCP 与 IP 密切相关，它是 IP 网络上所使用的协议。如果你想要使用 DHCP 提供服务的话，那么在整条通信链路上就需要 <code>DHCP 服务器</code>的存在，连接到网络的设备使用 DHCP 协议从 DHCP 服务器请求 IP 地址。DHCP 服务器会为设备分配一个唯一的 IP 地址。</p><blockquote><p>除了 IP 地址外，DHCP 服务器还会把子网掩码，默认路由，DNS 服务器告诉你。</p></blockquote><h3 id="dhcp-服务器" tabindex="-1">DHCP 服务器 <a class="header-anchor" href="#dhcp-服务器" aria-label="Permalink to &quot;DHCP 服务器&quot;">​</a></h3><p>现在，你不需要手动配置 IP 地址，也不再需要管理 IP 地址了，管理权已经移交给了 DHCP 服务器，DHCP 服务器会维护 IP 地址池，在网络上启动时会将地址租借给启用 DHCP 的客户端。</p><p>由于 IP 地址是<strong>动态的(临时分配)**而不是**静态的(永久分配)</strong>，因此不再使用的 IP 地址会自动返回 IP 地址池中进行重新分配。</p><blockquote><p>那么 DHCP 服务器由谁维护呢？</p></blockquote><p>网络管理员负责建立 DHCP 服务器，并以租约的形式向启用 DHCP 的客户端提供地址配置，啊，既然不需要我管理，那就很舒服了～</p><p>好了，现在你能舒舒服服的开发了，你用 postman 配了一条 192.168.1.4/x/x 的接口进行请求，请求能够顺利进行，但是过了一段时间后，你发现 192.168.1.4/x/x 这个接口请求不通了，这是为啥呢？然后你用 <code>ipconfig</code> 查询了一下自己的 IP 地址，发现 IP 地址变成了 192.168.1.7，怎么我用着用着 IP 地址还改了？DHCP 是个垃圾，破玩意！！@#¥%¥%……¥%</p><p>其实，这也是一个 DHCP 服务器的一个功能，DHCP 服务器通常为每个客户端分配一个<strong>唯一的动态 IP 地址</strong>，当该 IP 地址的<strong>客户端租约到期</strong>时，该地址就会更改。</p><p>唯一意思说的就是，如果你手动设置了一个静态 IP，同时 DHCP 服务器分配了一个动态 IP，这个动态 IP 和静态 IP 一样，那么必然会有一个客户端无法上网。</p><blockquote><p>我就遇到过这种情况，我使用虚拟机配置的静态 IP 是192.168.1.8，手机使用 DHCP 也同样配置了 192.168.1.8 的 IP 地址，此时我的虚拟机还没有接入网络，当我接入网络时，我怎样也连不上虚拟机了，一查才发现 IP 地址冲突了 ......</p></blockquote><p>虽然 DHCP 服务器能提供 IP 地址，但是他怎么知道哪些 IP 地址空闲，哪些 IP 地址正在使用呢？</p><p>实际上，这些信息都配置在了<code>数据库</code>中，下面我们就来一起看一下 DHCP 服务器维护了哪些信息。</p><ul><li>网络上所有有效的 TCP/IP 配置参数</li></ul><p>这些参数主要包括<strong>主机名（Host name）、DHCP 客户端（DHCP client）、域名（Domain name）、IP 地址IP address）、网关（Netmask）、广播地址（Broadcast address）、默认路由（default rooter）</strong>。</p><ul><li>有效的 IP 地址和排除的 IP 地址，保存在 IP 地址池中等待分配给客户端</li><li>为某些特定的 DHCP 客户端保留的地址，这些地址是静态 IP，这样可以将单个 IP 地址一致地分配给单个DHCP 客户端</li></ul><p>好了，现在你知道 DHCP 服务器都需要保存哪些信息了，并且看过上面的内容，你应该知道一个 DHCP 的组件有哪些了，下面我们就来聊一聊 DHCP 中都有哪些组件，这些组件缺一不可。</p><h3 id="dhcp-的组件" tabindex="-1">DHCP 的组件 <a class="header-anchor" href="#dhcp-的组件" aria-label="Permalink to &quot;DHCP 的组件&quot;">​</a></h3><p>使用 DHCP 时，了解所有的组件很重要，下面我为你列出了一些 DHCP 的组件和它们的作用都是什么。</p><ul><li><code>DHCP Server</code>，DHCP 服务器，这个大家肯定都知道，因为我们上面就一直在探讨 DHCP 服务器的内容，使用 DHCP ，是一定要有 DHCP 服务器的，要不然谁给你提供服务呢？</li><li><code>DHCP Client</code>，DHCP 客户端，这个大家应该也知道，毕竟只有一个服务端不行啊，没有客户端你为谁服务啊？DHCP 的客户端可以是<strong>计算机、移动设备或者其他需要连接到网络的任何设备，默认情况下，大多数配置为接收 DHCP 信息</strong>。</li><li><code>Ip address pool</code>: 你得有 IP 地址池啊，虽然说你 DHCP 提供服务，但是你也得有工具啊，没有工具玩儿啥？IP 地址池是 DHCP 客户端可用的地址范围，这个地址范围通常由最低 -&gt; 最高顺序发送。</li><li><code>Subnet</code>：这个组件是子网，IP 网络可以划分一段一段的子网，子网更有助于网络管理。</li><li><code>Lease</code>：租期，这个表示的就是 IP 地址续约的期限，同时也代表了客户端保留 IP 地址信息的时间长度，一般租约到期时，客户端必须续约。</li><li><code>DHCP relay</code>：DHCP 中继器，这个一般比较难想到，DHCP 中继器一般是路由器或者主机。DHCP 中继器通常应对 DHCP 服务器和 DHCP 客户端不再同一个网断的情况，如果 DHCP 服务器和 DHCP 客户端在同一个网段下，那么客户端可以正确的获得动态分配的 IP 地址；如果不在的话，就需要使用 DHCP 中继器进行中继代理。</li></ul><p>现在 DHCP 的组件你了解后，下面我就要和你聊聊 DHCP 的工作机制了。</p><h2 id="dhcp-工作机制" tabindex="-1">DHCP 工作机制 <a class="header-anchor" href="#dhcp-工作机制" aria-label="Permalink to &quot;DHCP 工作机制&quot;">​</a></h2><p>在聊 DHCP 工作机制前，先来看一下 DHCP 的报文消息</p><h3 id="dhcp-报文" tabindex="-1">DHCP 报文 <a class="header-anchor" href="#dhcp-报文" aria-label="Permalink to &quot;DHCP 报文&quot;">​</a></h3><p>DHCP 报文共有一下几种：</p><ul><li><strong>DHCP DISCOVER</strong> ：客户端开始 DHCP 过程发送的包，是 DHCP 协议的开始</li><li><strong>DHCP OFFER</strong> ：服务器接收到 DHCPDISCOVER 之后做出的响应，它包括了给予客户端的 IP 租约过期时间、服务器的识别符以及其他信息</li><li><strong>DHCP REQUEST</strong> ：客户端对于服务器发出的 DHCPOFFER 所做出的响应。在续约租期的时候同样会使用。</li><li><strong>DHCP ACK</strong> ：服务器在接收到客户端发来的 DHCPREQUEST 之后发出的成功确认的报文。在建立连接的时候，客户端在接收到这个报文之后才会确认分配给它的 IP 和其他信息可以被允许使用。</li><li><strong>DHCP NAK</strong> ：DHCPACK 的相反的报文，表示服务器拒绝了客户端的请求。</li><li><strong>DHCP RELEASE</strong> ：一般出现在客户端关机、下线等状况。这个报文将会使 DHCP 服务器释放发出此报文的客户端的 IP 地址</li><li><strong>DHCP INFORM</strong> ：客户端发出的向服务器请求一些信息的报文</li><li><strong>DHCP DECLINE</strong> :当客户端发现服务器分配的 IP 地址无法使用（如 IP 地址冲突时），将发出此报文，通知服务器禁止使用该 IP 地址。</li></ul><p>DHCP 的工作机制比较简单，无非就是客户端向服务器租借 IP ，服务器提供 IP 给客户端的这个过程呗。嗯，你很聪明，大致是这样的，不过有一些细节需要注意下，下面我通过两张图来和你聊一下。</p><p>关于从 DHCP 中获取 IP 地址的流程，主要分为两个阶段。</p><p>第一个阶段是 DHCP 查找包的阶段</p><p>查找包的阶段主要分为两步：第一步是 DHCP 发现包，第二步是 DHCP 提供包。</p><p>DHCP 客户端在通信链路上发起<code>广播</code>，看看链路上有没有能提供 DHCP 包的服务器，然后通信链路上的各个节点会检查自己是否能够提供 DHCP 包，这时 DHCP 服务器说它能够提供 DHCP 包，然后 DHCP 就发出一个 DHCP 包沿着通信链路返回给 DHCP 客户端。</p><p>第二个阶段是 DHCP 的请求阶段。</p><p>DHCP 的请求包也分为两步：第一步是 DHCP 请求包，第二步是 DHCP 确认包。</p><p>DHCP 客户端在通信链路上发起 DHCP 请求包，请求包主要是告诉 DHCP 服务器，它想要用上一步提供的网络设置，然后 DHCP 服务器向 DHCP 客户端发送确认包，表示允许 DHCP 客户端使用第二步发送的网络设置。</p><p>至此，DHCP 的网络设置就结束了，然后通信链路上的主机之间就可以进行 TCP/IP 通信了。</p><p>当不需要 IP 地址时，可以发送 <code>DHCP 解除包(DHCP RELEASE)</code>进行解除。另外，DHCP 的设置中通常会有一个租期时间的设定，DHCP 客户端在这个时限内可以发送 DHCP 请求包通知想要延长这个期限。</p><h3 id="dhcp-状态机" tabindex="-1">DHCP 状态机 <a class="header-anchor" href="#dhcp-状态机" aria-label="Permalink to &quot;DHCP 状态机&quot;">​</a></h3><p>我们上面知道 DHCP 会发送几种请求包，我们知道，动作肯定伴随着状态的更改，DHCP 也是一样的，在 DHCP 发送/接收各种包的时候，其状态也在发生相应的改变。DHCP 协议可以在客户端和服务器上运行状态机。状态决定了协议接下来要处理的消息类型。</p><p>状态之间的转换（箭头）是由于接收和发送消息或者计时器到期才发生的转换。下面是 DHCP 的状态轮转图。</p><p>客户端在开始时没有消息，此时处于 <code>INIT</code> 状态，然后客户端会在通信链路上发起一个广播 <code>DHCP DISCOVER</code>。</p><p>在 <code>Selecting</code> 选择状态下，客户端会收集 DHCPOFFER 消息，直到确定要使用的地址和服务器为止。</p><p>一旦 DHCP 客户端做好选择后，它就会发送 DHCPREQUEST 消息并进入 <code>Requesting 状态</code>，在这个状态下它很可能收到并不需要的 ACK 响应，如果这个状态下没有找到合适的地址的话，那么客户端就会发送<code>DHCPDECLINE</code> 并恢复为 INIT 状态，但是这种发生的概率比较小。</p><p>在处于 Requesting 状态下的客户端很可能接受发送过来的 DHCPACK 消息，获取超时时间 <code>T1</code> 和 <code>T2</code>，然后进入 <code>Bound</code> 绑定状态，在这个状态下可以使用地址直到地址过期。</p><p>在第一个计时器 T1 到期时，客户端会进入 <code>renewing</code> 续订状态，并重新尝试建立租约时间，如果收到新的 ACK 消息就表示续订成功，然后就恢复为 Bound 状态。</p><p>如果没有收到 ACK 那么 T2 会最终过期进入 <code>Rebinding</code> 状态，进入这个状态的客户端会重新尝试获取地址，如果最终的租约到期，那么客户端必须放弃租约地址，并且如果没有其他地址或网络连接要使用，客户端将断开连接。</p><h3 id="dhcp-冲突" tabindex="-1">DHCP 冲突 <a class="header-anchor" href="#dhcp-冲突" aria-label="Permalink to &quot;DHCP 冲突&quot;">​</a></h3><p>现在我们讨论一下 DHCP 冲突的问题，DHCP 冲突其实就是 IP <code>重了</code>，当一个子网中两个或者更多主机配置了相同的 IP 地址时，就会发生 IP 冲突的现象。发生这种情况可能导致的后果是两个冲突的主机混在一起，一台主机可能接收了另一台主机的数据包。</p><blockquote><p>那么造成这种情况的原因是啥呢？</p></blockquote><p>造成这种情况的原因有很多，这里我列举两个可能出现的情况：</p><ul><li>第一种情况是一台主机配置了静态 IP 地址，这台主机联网后，其 IP 地址不会在 DHCP 服务器中，然后另外一个主机入网，DHCP 服务器给这台主机自动分配了相同的 IP 地址，这两个地址就产生了 IP 冲突。</li><li>第二种情况是，客户端从 DHCP 服务器获得了 IP 地址，然后这台主机下线了，随着租约到期，DHCP 会将这个 IP 地址又分配给了其他主机，等到这个主机重新上线后，由于某种原因，计算机无法访问 DHCP 服务器，这种情况下会造成 IP 冲突。</li></ul><p>当检测到 IP 冲突时，通常 Windows 系统和 Mac 系统会弹出 IP 冲突的弹窗。</p><h2 id="dhcp-中继代理" tabindex="-1">DHCP 中继代理 <a class="header-anchor" href="#dhcp-中继代理" aria-label="Permalink to &quot;DHCP 中继代理&quot;">​</a></h2><p>常规家庭网络（土豪除外）中大多数都只有一个<code>以太网</code>，也就是 LAN 网段，一个 DHCP 服务器完全可以满足 LAN 中的客户机使用。但是，在更复杂的网络中，比如企业或者学校，一台 DHCP 服务器显然就无法满足了。因此，这种情况下，往往需要 DHCP 的统一管理，具体实现方式可以通过 <code>DHCP 中继代理</code> 来转发 DHCP 流量，如下图所示。</p><p>如上图所示，存在两个网段 A 和网段 B，DHCP 客户机和 DHCP 服务器不在一个网段内，所以我们在通信链路上架设了一个中继代理，DHCP 客户机通过访问中继代理以达到访问 DHCP 服务器的目的。</p><p>使用这种方式，我们不再需要在每个网段都设置一个 DHCP 服务器，只需要在每个网段架设一个中继代理即可。它可以设置 DHCP 服务器的 IP 地址，从而可以在 DHCP 服务器上为每个网段注册 IP 地址的分配范围。</p><p>DHCP 客户端会向 DHCP 中继代理发送 DHCP 请求包，而 DHCP 中继代理在收到这个广播包之后再以单播的形式发送给 DHCP 服务器。服务器收到该包以后再向 DHCP 中继代理返回应答，并由 DHCP 中继代理将此包发送给 DHCP 客户端。</p><h2 id="dhcp-认证" tabindex="-1">DHCP 认证 <a class="header-anchor" href="#dhcp-认证" aria-label="Permalink to &quot;DHCP 认证&quot;">​</a></h2><p><strong>我们总是假想所有情况都能够顺利进行，害怕出问题，这也许意味着我永远只是个初级程序员吧</strong>。我们上面探讨的 DHCP 服务器都是合理的、合法的，但是互联网是一把双刃剑，不是所有人都是合法公民。如果假设了一个未经授权的 DHCP 服务器怎么办？它很可能会对网络造成影响。</p><p>为了避免这些问题，在 [RFC3118] 中指定了一种认证 DHCP 消息的方法。 它定义了一个 DHCP 选项，即Authentication 选项，如下所示</p><p>认证选项的主要目的就是<strong>确定 DHCP 消息是否来自一个授权的发送方</strong>。</p><p>身份验证的代码（code）属性值是 90，而长度（Length）给出了选项中的字节数（不包括代码和长度字段的字节）。如果协议（Protocol）和算法（Algorithm）属性被设置为 0 ，则<code>认证信息</code>字段将保存一个简单的共享配置的 token，token 大家开发应该都接触过把，就是一条认证信息。只要配置令牌在客户端和服务器上匹配，这条消息就会被接受。</p><p>我们上面聊到的只是其中的一种，还有一种更安全的方法是涉及所谓的<code>延迟身份认证</code>，如果协议和算法都被设置为 1，就表示使用了延迟身份认证。在这种情况下，客户端的 DHCPDISCOVER 消息或 DHCPINFORM 消息包括身份验证选项，并且服务器以其 DHCPOFFER 或 DHCPACK 消息中包含的身份验证信息进行响应。这个认证信息中包括一个<code>消息认证码</code>，它提供对发送方的认证和消息的完整性校验。RDM 表示中继检测，中继检测包括一个单项递增的值，只要经过一个代理中继，那么这个中继检测的值就会 + 1。</p><p>虽然 DHCP 认证能够确保安全性，但是它没有被广泛使用，原因有两点：</p><ul><li>首先，该方法要求在 DHCP 服务器和每个需要身份验证的客户端之间分配共享密钥。</li><li>其次，在 DHCP 已经被广泛使用之后，才指定了 Authentication 选项。</li></ul><h2 id="总结" tabindex="-1">总结 <a class="header-anchor" href="#总结" aria-label="Permalink to &quot;总结&quot;">​</a></h2><p>这篇文章我和你探讨了计算机网络中一个比较容易忽视的概念，为什么说他容易忽视呢？因为我们平常开发过程中基本上不会管 IP 地址的配置的，也就是环境搭建的时候会用到一些，但是要系统学习计算机网络的话，DHCP 的重要性不可忽视，DHCP 包括工作机制、DHCP 报文消息，DHCP 状态机、DHCP 认证这些都是需要你了解并掌握的。</p>',70);function r(e,n,s,h,I,u){return C(),D("div",null,[P("h1",p,[H(t(e.$frontmatter.title)+" ",1),l]),i])}const b=o(d,[["render",r]]);export{m as __pageData,b as default};
